/* HealingMart Calculator Loader v1.1.0 */
(function (w, d) {
  "use strict";
  const script = d.currentScript;
  if (!script) return;
  const explicitBase = script.dataset.base || "";
  const src = script.src || "";
  const base = explicitBase || src.replace(/\/dist\/js\/hm-calc-loader[^/]*\.js(?:\?.*)?$/, "");
  const dist = base.replace(/\/$/, "") + "/dist";
  const loaded = new Map();

  function loadScript(url) {
    if (loaded.has(url)) return loaded.get(url);
    const p = new Promise((resolve, reject) => {
      const s = d.createElement("script");
      s.src = url;
      s.defer = true;
      s.onload = resolve;
      s.onerror = () => reject(new Error("로드 실패: " + url));
      d.head.appendChild(s);
    });
    loaded.set(url, p);
    return p;
  }
  function ensureCss() {
    const id = "hm-calc-css-v1";
    if (d.getElementById(id)) return;
    const link = d.createElement("link");
    link.id = id;
    link.rel = "stylesheet";
    link.href = dist + "/css/hm-calc.v1.css";
    d.head.appendChild(link);
  }
  async function boot() {
    ensureCss();
    if (!w.HM_CALC || !w.HM_CALC.mount) await loadScript(dist + "/js/hm-calc-core.v1.min.js");
    if (!w.HM_CALC_SOUND) await loadScript(dist + "/js/hm-calc-sound.v1.min.js");
    if (!w.HM_CALC_SHARE) await loadScript(dist + "/js/hm-calc-share.v1.min.js");
    const roots = Array.from(d.querySelectorAll("[data-hm-calculator]:not([data-hm-calculator-mounted])"));
    for (const root of roots) {
      const id = root.dataset.hmCalculator;
      if (!id) continue;
      try {
        if (!w.HM_CALC.has(id)) await loadScript(dist + "/calculators/" + encodeURIComponent(id) + ".min.js");
        w.HM_CALC.mount(root, id);
        if (w.HM_CALC_SOUND && w.HM_CALC_SOUND.mount) w.HM_CALC_SOUND.mount(root);
        if (w.HM_CALC_SHARE && w.HM_CALC_SHARE.mount) w.HM_CALC_SHARE.mount(root);
      } catch (err) {
        root.innerHTML = '<div class="hm-calc-error">계산기를 불러오지 못했습니다. 잠시 후 다시 시도해 주세요.</div>';
        console.error(err);
      }
    }
  }
  if (d.readyState === "loading") d.addEventListener("DOMContentLoaded", boot, { once: true }); else boot();
})(window, document);
